var device = metadata.deviceName;
var newMsg = {};

// ฟังก์ชันแกะกล่องป้องกันข้อมูลพัง
function safeParse(jsonStr) {
    var obj = {};
    if (jsonStr) {
        try {
            var parsed = JSON.parse(jsonStr);
            while (typeof parsed === 'string') { parsed = JSON.parse(parsed); }
            if (typeof parsed === 'object' && parsed !== null) { obj = parsed; }
        } catch(e) {}
    }
    return obj;
}

var powerState = safeParse(metadata.meters_power_state);
var energyState = safeParse(metadata.meters_energy_state);

// 1. จัดการ Power (รวมยอดชั้น)
if (msg.power_total !== undefined && msg.power_total !== null && msg.power_total !== "") {
    powerState[device] = Number(msg.power_total) || 0;
    var totalPower = 0;
    for (var m in powerState) { totalPower += Number(powerState[m]) || 0; }
    newMsg.meters_power_state = JSON.stringify(powerState);
    newMsg.power_total_floor = totalPower;
}

// 2. จัดการ Energy (รวมยอดชั้น)
if (msg.energy_kwh !== undefined && msg.energy_kwh !== null && msg.energy_kwh !== "") {
    energyState[device] = Number(msg.energy_kwh) || 0;
    var totalEnergy = 0;
    for (var n in energyState) { totalEnergy += Number(energyState[n]) || 0; }
    newMsg.meters_energy_state = JSON.stringify(energyState);
    newMsg.energy_kwh_floor = totalEnergy;
}

// 3. รับค่า Consumption จากมิเตอร์ตรงๆ มาคำนวณ CO2 และเซฟลงตึกชั้นเลย!
if (msg.Energy_consumption !== undefined && msg.Energy_consumption !== null) {
    newMsg.Energy_consumption = Number(msg.Energy_consumption);
    newMsg.CO2 = newMsg.Energy_consumption * 0.5986;
    newMsg.E_charge = newMsg.Energy_consumption * 4.5;
}

return {msg: newMsg, metadata: metadata, msgType: msgType};

configuration.tbelScript:
// 1. ดึงข้อมูลสถานะล่าสุดของมิเตอร์ทุกตัวในชั้น (จากที่ดึงมาในขั้นที่ 2)
var state = {};
if (metadata.meters_state_json) {
    try { 
        state = JSON.parse(metadata.meters_state_json); 
    } catch(e) {}
}

// 2. อัปเดตข้อมูลเฉพาะมิเตอร์ตัวที่เพิ่งส่งข้อมูลเข้ามา (ระบบดึง Device Name ให้อัตโนมัติ)
state[metadata.deviceName] = {
    power: parseFloat(msg.power_total) || 0,
    energy: parseFloat(msg.energy_kWh) || 0
};

// 3. วนลูปคำนวณผลรวมพลังงานของมิเตอร์ "ทุกตัว" ในชั้นนี้
var totalPower = 0;
var totalEnergy = 0;
for (var meter in state) {
    totalPower += state[meter].power;
    totalEnergy += state[meter].energy;
}

// 5. สร้าง Message ใหม่เพื่อบันทึกผลลัพธ์
var newMsg = {
    meters_state_json: JSON.stringify(state), // ซ่อนค่าแยกมิเตอร์ไว้ในตัวแปรนี้เพื่อใช้คำนวณรอบหน้า
    power_total_floor: totalPower,
    energy_kWh_floor: totalEnergy,
};

return {msg: newMsg, metadata: metadata, msgType: msgType};

configuration.jsScript:
// เช็คว่ามีตัวแปรส่งมาจริง และค่าต้องไม่ใช่ null และไม่ใช่ข้อความว่าง ""
var hasPower = msg.hasOwnProperty('power_total') && msg.power_total !== null && msg.power_total !== "";
var hasEnergy = msg.hasOwnProperty('energy_kwh') && msg.energy_kwh !== null && msg.energy_kwh !== "";

return hasPower || hasEnergy;

var floor = metadata.floorName;
var newMsg = {};

function safeParse(jsonStr) {
    var obj = {};
    if (jsonStr) {
        try {
            var parsed = JSON.parse(jsonStr);
            while (typeof parsed === 'string') { parsed = JSON.parse(parsed); }
            if (typeof parsed === 'object' && parsed !== null) { obj = parsed; }
        } catch(e) {}
    }
    return obj;
}

var powerState = safeParse(metadata.floors_power_state);
var energyState = safeParse(metadata.floors_energy_state);
// 🌟 เพิ่ม State สำหรับจำค่า Consumption
var consumptionState = safeParse(metadata.floors_consumption_state);

// 1. รวม Power ของทุกชั้นในตึก
if (msg.power_total_floor !== undefined && msg.power_total_floor !== null && msg.power_total_floor !== "") {
    powerState[floor] = Number(msg.power_total_floor) || 0;
    var totalPower = 0;
    for (var f in powerState) { totalPower += Number(powerState[f]) || 0; }
    newMsg.floors_power_state = JSON.stringify(powerState);
    newMsg.power_total_building = totalPower;
}

// 2. รวม Energy สะสมของทุกชั้นในตึก
if (msg.energy_kwh_floor !== undefined && msg.energy_kwh_floor !== null && msg.energy_kwh_floor !== "") {
    energyState[floor] = Number(msg.energy_kwh_floor) || 0;
    var totalEnergy = 0;
    for (var f in energyState) { totalEnergy += Number(energyState[f]) || 0; }
    newMsg.floors_energy_state = JSON.stringify(energyState);
    newMsg.energy_kwh_building = totalEnergy;
}

// 3. จัดการ Consumption (แบบทดสอบจำค่า vs แบบโยนเข้ากระปุก)
if (msg.Energy_consumption !== undefined && msg.Energy_consumption !== null) {

    consumptionState[floor] = Number(msg.Energy_consumption) || 0;
    var totalConsumption = 0;
    for (var c in consumptionState) { totalConsumption += Number(consumptionState[c]) || 0; }
    
    // บันทึก State กลับไป และสร้างตัวแปรใหม่ที่บวกยอดแบบจำค่าแล้ว
    newMsg.floors_consumption_state = JSON.stringify(consumptionState);
    newMsg.Ec_total_building = totalConsumption;
    // -------------------------------------------------------------------

    // 🌟 [แบบที่ถูกต้อง] โยนค่าเข้ากระปุกตึกตรงๆ (เก็บไว้ดูเทียบกัน)
    newMsg.Energy_consumption = Number(msg.Energy_consumption);
    
    if (msg.CO2 !== undefined && msg.CO2 !== null) {
        newMsg.CO2 = Number(msg.CO2);
    }
    if (msg.E_charge !== undefined && msg.E_charge !== null) {
        newMsg.E_charge = Number(msg.E_charge);
    }
}

return {msg: newMsg, metadata: metadata, msgType: msgType};

