var newMsg = {};

// 1. ดึงค่ามิเตอร์เดิมกลับมา
if (metadata.orig_power !== undefined) newMsg.power_total = metadata.orig_power;
if (metadata.orig_energy !== undefined) newMsg.energy_kwh = metadata.orig_energy;
if (metadata.orig_consumption !== undefined) newMsg.Energy_consumption = metadata.orig_consumption;

// 🌟 2. ทริคสำคัญ: บวกเวลาเพิ่ม 1 มิลลิวินาที ป้องกัน Database เซฟทับบรรทัดเดิม!
if (metadata.ts) {
    metadata.ts = (Number(metadata.ts) + 1).toString();
} else {
    // กรณีข้อความไม่มีตราประทับเวลามา ให้ใช้เวลาปัจจุบันของ Server แทน
    metadata.ts = new Date().getTime().toString();
}

return {msg: newMsg, metadata: metadata, msgType: msgType};

